import{_ as e,o as i,c as r,a6 as o}from"./chunks/framework.DtxWasON.js";const h=JSON.parse('{"title":"Genesis Settings & Parameters","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/introduction/genesis-settings.md","filePath":"mainchain/introduction/genesis-settings.md"}'),t={name:"mainchain/introduction/genesis-settings.md"};function s(n,a,d,l,c,p){return i(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="genesis-settings-parameters" tabindex="-1">Genesis Settings &amp; Parameters <a class="header-anchor" href="#genesis-settings-parameters" aria-label="Permalink to &quot;Genesis Settings &amp; Parameters&quot;">​</a></h1><p>This document gives a brief explanation of each of the main parameters found in a network&#39;s <code>genesis.json</code>. Some parameters have been omitted for brevity.</p><p>With the exception of Chain Params, the following parameters are changeable on-chain via governance.</p><nav class="table-of-contents"><ul><li><a href="#chain-params">Chain Params</a></li><li><a href="#auth-params">Auth Params</a></li><li><a href="#beacon-params">Beacon Params</a></li><li><a href="#distribution-params">Distribution Params</a></li><li><a href="#enterprise-params">Enterprise Params</a></li><li><a href="#governance-params">Governance Params</a></li><li><a href="#slashing-params">Slashing Params</a></li><li><a href="#staking-params">Staking Params</a></li><li><a href="#wrkchain-params">WRKChain Params</a></li></ul></nav><h2 id="chain-params" tabindex="-1">Chain Params <a class="header-anchor" href="#chain-params" aria-label="Permalink to &quot;Chain Params&quot;">​</a></h2><ul><li><code>.genesis_time</code><br> Genesis block timestamp. E.g. 2022-06-08T14:00:00Z</li><li><code>.chain_id</code><br> ID of the current chain, E.g. <code>FUND-MainNet-2</code></li></ul><h2 id="auth-params" tabindex="-1">Auth Params <a class="header-anchor" href="#auth-params" aria-label="Permalink to &quot;Auth Params&quot;">​</a></h2><p>Auth parameters are changeable via governance</p><ul><li><code>.app_state.auth.params.max_memo_characters</code><br> The maximum number of characters allowed in a Tx memo, e.g. 256</li><li><code>.app_state.auth.params.tx_sig_limit</code><br> The maximum number of permitted signatures on a <code>multisig</code> Tx. E.g. 7</li><li><code>.app_state.auth.params.tx_size_cost_per_byte</code><br> The gas cost per byte for a Tx. E.g. 10</li></ul><h2 id="beacon-params" tabindex="-1">Beacon Params <a class="header-anchor" href="#beacon-params" aria-label="Permalink to &quot;Beacon Params&quot;">​</a></h2><p>Beacon parameters are changeable via governance</p><ul><li><code>.app_state.beacon.params.denom</code><br> Denomination used for BEACON fees. E.g. <code>nund</code></li><li><code>.app_state.beacon.params.fee_record</code><br> Fee for recording BEACON timestamps, in <code>params.denom</code>, E.g. 1000000000</li><li><code>.app_state.beacon.params.fee_register</code><br> One time fee for registering a BEACON with the network, in <code>params.denom</code>. E.g. 1000000000000</li></ul><h2 id="distribution-params" tabindex="-1">Distribution Params <a class="header-anchor" href="#distribution-params" aria-label="Permalink to &quot;Distribution Params&quot;">​</a></h2><p>Distribution parameters are changeable via governance</p><ul><li><code>.app_state.distribution.params.base_proposer_reward</code><br> Additional % of fees etc. given to the block proposer as a bonus. E.g. 0.010000000000000000</li><li><code>.app_state.distribution.params.bonus_proposer_reward</code><br> Additional % of fees etc. given to the block proposer, based on voting metrics calculated with each block. E.g. 0.040000000000000000</li><li><code>.app_state.distribution.params.community_tax</code><br> A fixed % of fees sent to the community pool each block. The spending of community pool coins can be decided via governance. E.g. 0.020000000000000000</li></ul><h2 id="enterprise-params" tabindex="-1">Enterprise Params <a class="header-anchor" href="#enterprise-params" aria-label="Permalink to &quot;Enterprise Params&quot;">​</a></h2><p>Enterprise parameters are changeable via governance</p><ul><li><code>.app_state.enterprise.params.decision_time_limit</code><br> The time (in seconds) after which a raised Enterprise Purchase Order will automatically be rejected if no decision has been made. E.g. 259200</li><li><code>.app_state.enterprise.params.denom</code><br> Denomination in which Enterprise FUND will be issued. E.g. nund</li><li><code>.app_state.enterprise.params.ent_signers</code><br> Comma separated list of wallet addresses authorised to accept/reject Enterprise FUND Purchase Orders.</li><li><code>.app_state.enterprise.params.min_Accepts</code><br> Minimum number of <code>params.ent_signers</code> required to make a decision on a Purchase Order.</li></ul><h2 id="governance-params" tabindex="-1">Governance Params <a class="header-anchor" href="#governance-params" aria-label="Permalink to &quot;Governance Params&quot;">​</a></h2><p>Governance parameters are changeable via governance</p><ul><li><code>.app_state.gov.deposit_params.max_deposit_period</code><br> Time in ns in which deposits are required to be made for a proposal. E.g. 1209600000000000 <code>.app_state.gov.deposit_params.min_deposit</code><br> Minumum deposit required in order for a proposal to be valid, and enter the voting period. E.g. 1000000000000nund</li><li><code>.app_state.gov.tally_params.quorum</code><br> Minimum percentage of total stake needed to vote for a result to be considered valid. E.g. 0.400000000000000000</li><li><code>.app_state.gov.tally_params.threshold</code><br> Minimum proportion of Yes votes for proposal to pass. E.g. 0.500000000000000000</li><li><code>.app_state.gov.tally_params.veto</code><br> Minimum value of Veto votes to Total votes ratio for proposal to be vetoed. E.g. 0.334000000000000000</li><li><code>.app_state.gov.voting_params.voting_period </code> Length of the voting period in ns. E.g. 1209600000000000</li></ul><h2 id="slashing-params" tabindex="-1">Slashing Params <a class="header-anchor" href="#slashing-params" aria-label="Permalink to &quot;Slashing Params&quot;">​</a></h2><p>Slashing parameters are changeable via governance</p><ul><li><code>.app_state.slashing.params.downtime_jail_duration</code><br> Cooldown period in ns, after being jailed for downtime that a node cannot unjail. E.g. 600000000000</li><li><code>.app_state.slashing.params.min_signed_per_window</code><br> min % of SignedBlocksWindow that must be signed in order to keep EV in pool of active EVs. Below this = jailed. E.g. 0.050000000000000000</li><li><code>.app_state.slashing.params.signed_blocks_window</code><br> number of blocks to monitor for missed/double sign etc. E.g. 10000</li><li><code>.app_state.slashing.params.slash_fraction_double_sign</code><br> % of stake to slash for double signing. E.g. 0.050000000000000000</li><li><code>.app_state.slashing.params.slash_fraction_downtime</code><br> % of stakes to slash for downtime . E.g. 0.000100000000000000</li></ul><h2 id="staking-params" tabindex="-1">Staking Params <a class="header-anchor" href="#staking-params" aria-label="Permalink to &quot;Staking Params&quot;">​</a></h2><p>Staking parameters are changeable via governance</p><ul><li><code>.app_state.staking.params.bond_denom</code><br> Staking denomination. E.g. nund</li><li><code>.app_state.staking.params.historical_entries</code><br> The n most recent historical entries are persisted. E.g. 3</li><li><code>.app_state.staking.params.max_entries</code><br> max simultaneous entries for either unbonding delegation or redelegation (per pair/trio). E.g. 7</li><li><code>.app_state.staking.params.max_validators</code><br> Maximum number of active validators in the current pool. E.g. 96</li><li><code>.app_state.staking.params.unbonding_time</code><br> duration in ns unbonding takes to complete. E.g. 1814400000000000</li></ul><h2 id="wrkchain-params" tabindex="-1">WRKChain Params <a class="header-anchor" href="#wrkchain-params" aria-label="Permalink to &quot;WRKChain Params&quot;">​</a></h2><p>WRKChain parameters are changeable via governance</p><ul><li><code>.app_state.wrkchain.params.denom</code><br> Denomination used for WRKChain fees. E.g. <code>nund</code></li><li><code>.app_state.wrkchain.params.fee_record</code><br> Fee for recording WRKChain hashes, in <code>params.denom</code>, E.g. 1000000000</li><li><code>.app_state.wrkchain.params.fee_register</code><br> One time fee for registering a WRKChain with the network, in <code>params.denom</code>. E.g. 1000000000000</li></ul>',30)])])}const g=e(t,[["render",s]]);export{h as __pageData,g as default};
